mapper.select:
SELECT p.id, p.code, p.name, p.area_mu, p.owner_id, s.name AS owner_name, p.status, p.updated_at, (SELECT c.name FROM planting_plan pp JOIN crop c ON pp.crop_id = c.id WHERE pp.plot_id = p.id AND pp.status IN ('in_progress','harvested') AND pp.deleted_at IS NULL ORDER BY pp.plan_start_date DESC LIMIT 1) AS current_crop_name FROM plot p LEFT JOIN staff s ON p.owner_id = s.id WHERE p.deleted_at IS NULL
AND p.code LIKE CONCAT('%', #{q.code}, '%')
AND p.name LIKE CONCAT('%', #{q.name}, '%')
AND p.owner_id = #{q.ownerId}
AND p.status = #{q.status}
ORDER BY p.updated_at DESC, p.id DESC
